import java.io.IOException;
import javax.servlet.http.*;

public class XssSafeServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        String sanitizedUserInput = sanitizeUserInput(userInput);

        String htmlResponse = "<html><body>User input: " + sanitizedUserInput + "</body></html>";

        response.setContentType("text/html");
        response.getWriter().println(htmlResponse);
    }

    private String sanitizeUserInput(String userInput) {
        // Replace characters that are significant in HTML with their respective HTML entities
        userInput = userInput.replace("&", "&amp;")
                             .replace("<", "&lt;")
                             .replace(">", "&gt;")
                             .replace("\"", "&quot;")
                             .replace("'", "&#39;");

        return userInput;
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
